class SegmentTreeMin {
    data: Array<Int64>
    size: Int
    INF: Int64

    func __init__(data: Array<Int64>, size: Int, INF: Int64) {
        self.data = data
        self.size = size
        self.INF = INF
    }

    static func build(arr: Array<Int64>, n: Int, inf: Int64) -> SegmentTreeMin {
        var base = 1
        while (base < n) {
            base = base * 2
        }
        var tree_data = Array<Int64>(size: 2 * base, 0)
        for i in 0 to 2*base-1 {
            tree_data[i] = inf
        }
        for i in 0 to n-1 {
            tree_data[base + i] = arr[i]
        }
        var i = base - 1
        while (i >= 1) {
            tree_data[i] = min(tree_data[2*i], tree_data[2*i+1])
            i = i - 1
        }
        return SegmentTreeMin(data: tree_data, size: base, INF: inf)
    }

    func query(l: Int, r: Int) -> Int64 {
        var l0 = l
        var r0 = r
        l0 = l0 + size
        r0 = r0 + size
        var res: Int64 = INF
        while (l0 <= r0) {
            if (l0 % 2 == 1) {
                res = min(res, data[l0])
                l0 = l0 + 1
            }
            if (r0 % 2 == 0) {
                res = min(res, data[r0])
                r0 = r0 - 1
            }
            l0 = l0 / 2
            r0 = r0 / 2
        }
        return res
    }
}

class SegmentTreeMax {
