        self.size = size
        self.NEG_INF = NEG_INF
    }

    static func build(arr: Array<Int64>, n: Int, neg_inf: Int64) -> SegmentTreeMax {
        var base = 1
        while (base < n) {
            base = base * 2
        }
        var tree_data = Array<Int64>(size: 2 * base, 0)
        for i in 0 to 2*base-1 {
            tree_data[i] = neg_inf
        }
        for i in 0 to n-1 {
            tree_data[base + i] = arr[i]
        }
        var i = base - 1
        while (i >= 1) {
            tree_data[i] = max(tree_data[2*i], tree_data[2*i+1])
            i = i - 1
        }
        return SegmentTreeMax(data: tree_data, size: base, NEG_INF: neg_inf)
    }

    func query(l: Int, r: Int) -> Int64 {
        var l0 = l
        var r0 = r
        l0 = l0 + size
        r0 = r0 + size
        var res: Int64 = NEG_INF
        while (l0 <= r0) {
            if (l0 % 2 == 1) {
                res = max(res, data[l0])
                l0 = l0 + 1
            }
            if (r0 % 2 == 0) {
                res = max(res, data[r0])
                r0 = r0 - 1
            }
            l0 = l0 / 2
            r0 = r0 / 2
        }
        return res
    }
}

func solve(nums: Array<Int64>): Int64 {
    let n = nums.size()
    if (n < 4) {
        return 0
    }
    let INF: Int64 = 1_000_000_000_000_000_000
    let NEG_INF: Int64 = -INF

    let prefix = Array<Int64>(size: n+1, 0)
    prefix[0] = 0
    for i in 0 to n-1 {
        prefix[i+1] = prefix[i] + nums[i]
    }

    let left_inc_bound = Array<Int>(size: n, 0)
    left_inc_bound[0] = 0
    for i in 1 to n-1 {
        if (nums[i] > nums[i-1]) {
            left_inc_bound[i] = left_inc_bound[i-1]
        } else {
            left_inc_bound[i] = i
        }
    }

    let left_dec_bound = Array<Int>(size: n, 0)
    left_dec_bound[0] = 0
    for i in 1 to n-1 {
        if (nums[i] < nums[i-1]) {
            left_dec_bound[i] = left_dec_bound[i-1]
        } else {
            left_dec_bound[i] = i
        }
    }

    let right_inc_bound = Array<Int>(size: n, 0)
    right_inc_bound[n-1] = n-1
    for i in n-2 down to 0 {
        if (nums[i] < nums[i+1]) {
            right_inc_bound[i] = right_inc_bound[i+1]
        } else {
            right_inc_bound[i] = i
        }
    }

    let candidate = Array<Int64>(size: n, INF)
    for i in 0 to n-1 {
        if (left_inc_bound[i] < i) {
            candidate[i] = prefix[left_inc_bound[i]]
        }
    }

    let seg_tree_candidate = SegmentTreeMin.build(candidate, n, INF)
    let seg_tree_prefix = SegmentTreeMax.build(prefix, n+1, NEG_INF)

    var best_ans: Int64 = NEG_INF
    for q in 2 to n-2 {
        if (right_inc_bound[q] >= q+1) {
            let L = left_dec_bound[q]
            let R = q - 1
            if (L <= R) {
                let min_candidate_val = seg_tree_candidate.query(L, R)
                var k_low: Int = q + 2
                var k_high: Int = right_inc_bound[q] + 1
                if (k_high > n) {
                    k_high = n
                }
                if (k_low <= k_high) {
                    let max_prefix_val = seg_tree_prefix.query(k_low, k_high)
                    let total_sum = max_prefix_val - min_candidate_val
                    if (total_sum > best_ans) {
                        best_ans = total_sum
                    }
                }
            }
        }
    }

    return best_ans
}
