struct SparseTableMin {
    var table: [[Int64]]
    var n: Int

    init(_ arr: [Int64]) {
        n = arr.count
        if n == 0 {
            table = []
            return
        }
        var k = 0
        while (1 << (k+1)) <= n {
            k += 1
        }
        table = [[Int64]](repeating: [Int64](repeating: 0, count: n), count: k+1)
        for i in 0..<n {
            table[0][i] = arr[i]
        }
        for j in 1...k {
            let step = 1 << (j-1)
            var i = 0
            while i + (1 << j) <= n {
                table[j][i] = min(table[j-1][i], table[j-1][i+step])
                i += 1
            }
        }
    }

    func query(_ left: Int, _ right: Int) -> Int64 {
        if left > right {
            return 1000000000000000000
        }
        let length = right - left + 1
        var j = 0
        while (1 << (j+1)) <= length {
            j += 1
        }
        let offset = right - (1 << j) + 1
        return min(table[j][left], table[j][offset])
    }
}

