func solve(nums: [Int64]) -> Int64 {
    let n = nums.count
    if n < 4 {
        return 0
    }

    // Precompute L: increasing from the left
    var L = Array(repeating: 0, count: n)
    L[0] = 0
    for i in 1..<n {
        if nums[i] > nums[i-1] {
            L[i] = L[i-1]
        } else {
            L[i] = i
        }
    }

    // Precompute Q: prefix sum
    var Q = Array(repeating: Int64(0), count: n+1)
    for i in 0..<n {
        Q[i+1] = Q[i] + nums[i]
    }

    // Precompute M_left_new
    var M_left_new = Array(repeating: Int64(Int64.max), count: n)
    var dq = [Int]()
    for p in 1..<n {
        let low = L[p]
        let high = p - 1
        if low > high {
            dq.removeAll()
            continue
        }
        while !dq.isEmpty && dq.first! < low {
            dq.removeFirst()
        }
        while !dq.isEmpty && Q[dq.last!] >= Q[p-1] {
            dq.removeLast()
        }
        dq.append(p-1)
        if dq.isEmpty {
            M_left_new[p] = Int64(Int64.max)
        } else {
            M_left_new[p] = Q[dq.first!]
        }
    }

    // Precompute DL: decreasing from the left
    var DL = Array(repeating: 0, count: n)
    DL[0] = 0
    for i in 1..<n {
        if nums[i] < nums[i-1] {
            DL[i] = DL[i-1]
        } else {
            DL[i] = i
        }
    }

    // Precompute R: increasing from the right
    var R = Array(repeating: 0, count: n)
    R[n-1] = n-1
    if n > 1 {
        for i in (0...(n-2)).reversed() {
            if nums[i] < nums[i+1] {
                R[i] = R[i+1]
            } else {
                R[i] = i
            }
        }
    }

    // Precompute st: sparse table for max in Q for the last increasing segment
    let LOGN = 18
    var st = Array(repeating: Array(repeating: Int64.min, count: n+1), count: LOGN)
    for i in 0...n {
        st[0][i] = Q[i]
    }
    for j in 1..<LOGN {
        let step = 1 << (j-1)
        for i in 0...(n) {
            if i + (1 << j) > n+1 {
                continue
            }
            st[j][i] = max(st[j-1][i], st[j-1][i+step])
        }
    }

    func queryMax(l: Int, r: Int) -> Int64 {
        if l > r {
            return Int64.min
        }
        let length = r - l + 1
        let j = Int(floor(log2(Double(length))))
        let step = 1 << j
        return max(st[j][l], st[j][r-step+1])
    }

    // Precompute st_min: sparse table for min in M_left_new for decreasing segment
    var st_min = Array(repeating: Array(repeating: Int64.max, count: n), count: LOGN)
    for i in 0..<n {
        st_min[0][i] = M_left_new[i]
    }
    for j in 1..<LOGN {
        let step = 1 << (j-1)
        for i in 0..<n {
            if i + step >= n {
                continue
            }
            st_min[j][i] = min(st_min[j-1][i], st_min[j-1][i+step])
        }
    }

    func queryMin(l: Int, r: Int) -> Int64 {
        if l > r {
            return Int64.max
        }
        let length = r - l + 1
        let j = Int(floor(log2(Double(length))))
        let step = 1 << j
        return min(st_min[j][l], st_min[j][r - step + 1])
    }

    // Iterate q to find the answer
    var ans = Int64.min
    for q in 1..<n-1 {
        if R[q] < q+1 {
            continue
        }
        let rHigh = min(n, R[q]+1)
        let g_val = queryMax(l: q+1, r: rHigh)
        if g_val == Int64.min {
            continue
        }
        if DL[q] > q-1 {
            continue
        }
        let d = DL[q]
        let f_val = queryMin(l: d, r: q-1)
        if f_val == Int64.max {
            continue
        }
        let total = g_val - f_val
        if total > ans {
            ans = total
        }
    }

    return ans
}
