func solve(nums: Array<Int64>): Int64 {
    let n = nums.count
    if n < 4 {
        return 0
    }
    var g = Array<Int64>(repeating: 0, count: n)
    g[0] = nums[0]
    for i in 1 ..< n {
        if nums[i] > nums[i-1] {
            g[i] = g[i-1] + nums[i]
        } else {
            g[i] = nums[i]
        }
    }
    let INF: Int64 = -1000000000000000000
    var f1 = Array<Int64>(repeating: INF, count: n)
    var f2 = Array<Int64>(repeating: INF, count: n)
    for i in 1 ..< n {
        if nums[i] < nums[i-1] {
            var cand1: Int64 = INF
            var cand2: Int64 = INF
            if i >= 2 && nums[i-1] > nums[i-2] {
                cand1 = g[i-1] + nums[i]
            }
            if f1[i-1] != INF {
                cand2 = f1[i-1] + nums[i]
            }
            f1[i] = max(cand1, cand2)
        }
        if nums[i] > nums[i-1] {
            var cand1: Int64 = INF
            var cand2: Int64 = INF
            if f1[i-1] != INF {
                cand1 = f1[i-1] + nums[i]
            }
            if f2[i-1] != INF {
                cand2 = f2[i-1] + nums[i]
            }
            f2[i] = max(cand1, cand2)
        }
    }
    var ans = INF
    for val in f2 {
        if val > ans {
            ans = val
        }
    }
    return ans
}
